def _local_path_from_curs_url(address: str) -> str:
    raw = unquote(address.strip())
    if raw.startswith("web+cursiv:"):
        raw = raw[len("web+cursiv:"):]

    parsed = urlparse(raw)
    if parsed.scheme != "curs.http":
        return "/"
    if parsed.netloc and parsed.netloc not in {_CURSIV_HOST, "cursiv.local", "localhost", "127.0.0.1"}:
        return "/"

    path = parsed.path or "/"
    if not path.startswith("/"):
        path = "/" + path
    if parsed.query:
        path += "?" + parsed.query
    return path


@app.get("/protocol/open", include_in_schema=False)
def protocol_open(url: str = Query("")):
    return RedirectResponse(_local_path_from_curs_url(url), status_code=307)


